const feed = $json.feed || $json;
let entries = feed.entry || [];
if (!Array.isArray(entries)) entries = [entries];
return entries.map((entry) => ({ json: { title: String(entry.title?._text || entry.title || '').replace(/\s+/g, ' ').trim(), source: 'arXiv', summary: String(entry.summary?._text || entry.summary || '').replace(/\s+/g, ' ').trim().slice(0, 500), url: String(entry.id?._text || entry.id || ''), published_date: String(entry.published?._text || entry.published || ''), created_at: new Date().toISOString(), status: 'New' } }));

const items = $input.all();
const keywords = ['ai', 'artificial intelligence', 'llm', 'gpt', 'agent', 'rag', 'multimodal', 'machine learning'];
const seen = new Set();
const out = [];
for (const item of items) {
  const key = String(item.json.url || item.json.title || '');
  if (!key || seen.has(key)) continue;
  seen.add(key);
  const text = `${String(item.json.title || '').toLowerCase()} ${String(item.json.summary || '').toLowerCase()}`;
  if (!keywords.some((k) => text.includes(k))) continue;
  out.push(item);
}
return out.slice(0, 8);

