function safeText(value, fallback = '') { const text = String(value ?? '').trim(); return text || fallback; }
function clamp(value) { const n = Number(value); if (!Number.isFinite(n)) return 0; return Math.max(1, Math.min(10, Math.round(n))); }
function hashText(text) { let hash = 5381; for (let i = 0; i < text.length; i++) { hash = ((hash << 5) + hash) + text.charCodeAt(i); hash = hash >>> 0; } return `h_${hash.toString(16)}`; }
const aiRaw = (($json.choices?.[0]?.message?.content) || '{"category":"unknown","lab_relevance":0,"practicality":0,"novelty":0,"recommended_action":"Watch","why_it_matters":"Model response missing"}').replace(/```json/g, '').replace(/```/g, '').replace(/^json\s*/i, '').trim();
let parsed; try { parsed = JSON.parse(aiRaw); } catch { parsed = { category: 'unknown', lab_relevance: 0, practicality: 0, novelty: 0, recommended_action: 'Watch', why_it_matters: 'Parsing failed' }; }
const original = $('Filter and Rank').item.json;
const lab = clamp(parsed.lab_relevance); const prac = clamp(parsed.practicality); const nov = clamp(parsed.novelty);
const final_score = Number(((lab + prac + nov) / 3).toFixed(2));
const title = safeText(original.title, 'untitled');
const url = safeText(original.url, '');
const hash_id = hashText(`${title.toLowerCase()}|${url.toLowerCase()}`);
const payload = { source: 'n8n.tools.feed', version: '1.0', generated_at: new Date().toISOString(), batch_id: `n8n-${new Date().toISOString().replace(/[:.]/g, '').replace('T', '-').slice(0, 15)}-${hash_id}`, data: [{ id: hash_id, hash_id, title, source: safeText(original.source), summary: safeText(original.summary), url, published_date: safeText(original.published_date), created_at: safeText(original.created_at, new Date().toISOString()), status: safeText(original.status, 'New'), category: safeText(parsed.category, 'unknown'), lab_relevance: lab, practicality: prac, novelty: nov, final_score, recommended_action: safeText(parsed.recommended_action, 'Watch'), why_it_matters: safeText(parsed.why_it_matters, 'Pending').slice(0, 220) }] };
return [{ json: { payload, timestamp: Math.floor(Date.now() / 1000).toString() } }];
